import anthropic

client = anthropic.Anthropic()

message = client.messages.create(
    model="claude-3-5-sonnet-20241022",  # Older model (supports prefill)
    max_tokens=1000,
    messages=[
        {
            "role": "user",
            "content": "Please describe yourself using only JSON"
        },
        {
            "role": "assistant",  # ← Assistant role
            "content": "{"  # ← YOUR PREFILL TEXT (opening brace)
        }
    ]
)

print(message.content[0].text)
# "name": "Claude", "age": 2, "personality": "helpful"
# ← Raw JSON, no markdown, no preamble!

import anthropic

client = anthropic.Anthropic()

# ❌ WITHOUT PREFILL — Claude adds markdown
message = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    max_tokens=1000,
    messages=[
        {
            "role": "user",
            "content": "Output: name=John, age=30 in JSON"
        }
    ]
)

print(message.content.text)
# ```json
# {
#   "name": "John",
#   "age": 30
# }
# ```
# ← Markdown wrappers!

# ✅ WITH PREFILL — Raw JSON only
message = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    max_tokens=1000,
    messages=[
        {
            "role": "user",
            "content": "Output: name=John, age=30 in JSON"
        },
        {
            "role": "assistant",
            "content": "{"  # ← Prefill opening brace
        }
    ]
)

print(message.content.text)
# "name": "John", "age": 30
# ← Raw JSON, no markdown!

import anthropic

client = anthropic.Anthropic()

# Prefill for multiple choice
message = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    max_tokens=1,  # Force single token
    messages=[
        {
            "role": "user",
            "content": "Latin for Ant? (A) Apoidea, (B) Rhopalocera, (C) Formicidae"
        },
        {
            "role": "assistant",
            "content": "The answer is ("  # ← Prefill answer format
        }
    ]
)

print(message.content.text)
# "C)"
# ← Single letter, no explanation!
